/* style.css - 國語複習簡報樣式表 */

/* 全域設定 */
:root {
    --primary: #5c7cfa;
    --primary-light: #edf2ff;
    --accent: #ff922b;
    --success: #37b24d;
    --danger: #f03e3e;
    --text-color: #2b2b2b;
    --text-muted: #868e96;
    --glass-bg: rgba(255, 255, 255, 0.75);
    --glass-border: rgba(255, 255, 255, 0.4);
    --shadow-sm: 0 4px 6px -1px rgba(0, 0, 0, 0.05), 0 2px 4px -1px rgba(0, 0, 0, 0.03);
    --shadow-md: 0 10px 15px -3px rgba(0, 0, 0, 0.08), 0 4px 6px -2px rgba(0, 0, 0, 0.04);
    --shadow-lg: 0 20px 25px -5px rgba(0, 0, 0, 0.1), 0 10px 10px -5px rgba(0, 0, 0, 0.04);
    --font-cute: 'Fredoka', 'Noto Sans TC', sans-serif;
    --font-normal: 'Noto Sans TC', sans-serif;
}

* {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
    user-select: none;
}

body {
    font-family: var(--font-normal);
    color: var(--text-color);
    background: #f1f3f5;
    overflow: hidden;
    height: 100vh;
    width: 100vw;
}

/* 背景音樂控制 */
.audio-control {
    position: fixed;
    top: 20px;
    right: 20px;
    z-index: 1000;
    width: 50px;
    height: 50px;
    background: var(--glass-bg);
    backdrop-filter: blur(8px);
    border: 2px solid var(--glass-border);
    border-radius: 50%;
    display: flex;
    justify-content: center;
    align-items: center;
    cursor: pointer;
    box-shadow: var(--shadow-md);
    transition: transform 0.2s, background 0.2s;
}

.audio-control:hover {
    transform: scale(1.1);
    background: #fff;
}

.audio-control .icon {
    font-size: 20px;
}

/* 投影片場景基礎 */
.scene {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: center;
    opacity: 0;
    pointer-events: none;
    transition: opacity 0.5s ease-in-out, transform 0.5s cubic-bezier(0.1, 0.8, 0.2, 1);
    transform: translateY(20px);
    padding: 40px 20px;
}

.scene.active {
    opacity: 1;
    pointer-events: auto;
    transform: translateY(0);
}

/* ------------------ 首頁樣式 ------------------ */
#home {
    background: linear-gradient(180deg, #d0ebff 0%, #a5d8ff 60%, #e7f5ff 100%);
    overflow: hidden;
}

.sky {
    position: absolute;
    top: 0;
    width: 100%;
    height: 50%;
}

.cloud {
    position: absolute;
    background: #fff;
    border-radius: 100px;
    opacity: 0.8;
}

.cloud::before, .cloud::after {
    content: '';
    position: absolute;
    background: #fff;
    border-radius: 50%;
}

.cloud1 {
    width: 150px;
    height: 50px;
    top: 10%;
    left: 10%;
    animation: floatClouds 30s linear infinite alternate;
}
.cloud1::before { width: 70px; height: 70px; top: -30px; left: 15px; }
.cloud1::after { width: 50px; height: 50px; top: -20px; right: 20px; }

.cloud2 {
    width: 200px;
    height: 60px;
    top: 25%;
    right: 15%;
    animation: floatClouds 45s linear infinite alternate-reverse;
}
.cloud2::before { width: 90px; height: 90px; top: -45px; left: 20px; }
.cloud2::after { width: 70px; height: 70px; top: -30px; right: 30px; }

@keyframes floatClouds {
    0% { transform: translateX(0); }
    100% { transform: translateX(100px); }
}

.banner {
    z-index: 10;
    text-align: center;
    background: rgba(255, 255, 255, 0.45);
    backdrop-filter: blur(16px);
    border: 2px solid rgba(255, 255, 255, 0.6);
    border-radius: 30px;
    padding: 40px 60px;
    box-shadow: var(--shadow-lg);
    max-width: 90%;
    animation: popIn 0.8s cubic-bezier(0.175, 0.885, 0.32, 1.275);
}

.school-badge {
    display: inline-block;
    background: var(--primary);
    color: #fff;
    font-size: 14px;
    font-weight: bold;
    padding: 6px 16px;
    border-radius: 20px;
    margin-bottom: 20px;
    letter-spacing: 2px;
}

.banner h1 {
    font-size: 56px;
    font-family: var(--font-cute);
    color: #1c7ed6;
    text-shadow: 0 4px 10px rgba(0,0,0,0.05);
    margin-bottom: 10px;
}

.banner h2 {
    font-size: 32px;
    font-weight: 800;
    color: var(--text-color);
    margin-bottom: 15px;
    letter-spacing: 4px;
}

.lessons {
    font-size: 18px;
    color: #495057;
    margin-bottom: 30px;
    font-weight: 500;
}

.btn {
    font-family: var(--font-cute);
    font-size: 20px;
    font-weight: 700;
    padding: 14px 40px;
    border: none;
    border-radius: 50px;
    cursor: pointer;
    box-shadow: var(--shadow-md);
    transition: all 0.2s ease-in-out;
}

.btn-start {
    background: linear-gradient(135deg, #ff922b 0%, #f76707 100%);
    color: white;
}

.btn-start:hover {
    transform: scale(1.05) translateY(-2px);
    box-shadow: 0 15px 20px rgba(247, 103, 7, 0.3);
}

.btn-start:active {
    transform: scale(0.98);
}

.mountains {
    position: absolute;
    bottom: -10px;
    width: 100%;
    height: 25%;
    pointer-events: none;
}

.mountain {
    position: absolute;
    bottom: 0;
    width: 120%;
    height: 100%;
    border-radius: 50% 50% 0 0;
}

.mountain-back {
    background: #74c0fc;
    left: -10%;
    height: 110%;
    opacity: 0.5;
}

.mountain-front {
    background: #4dabf7;
    right: -10%;
    height: 80%;
    opacity: 0.7;
}

@keyframes popIn {
    0% { transform: scale(0.8); opacity: 0; }
    100% { transform: scale(1); opacity: 1; }
}

/* ------------------ 主選單樣式 ------------------ */
#lobby {
    background: linear-gradient(135deg, #e3fafc 0%, #c5f6fa 100%);
}

.lobby-header {
    text-align: center;
    margin-bottom: 30px;
    animation: fadeInDown 0.6s ease-out;
}

.lobby-header h3 {
    font-size: 36px;
    font-weight: 900;
    color: #0b7285;
}

.lobby-header p {
    font-size: 16px;
    color: #495057;
    margin-top: 5px;
}

.lobby-grid {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 20px;
    max-width: 1100px;
    width: 100%;
    margin-bottom: 30px;
    perspective: 1000px;
}

.lobby-card {
    background: var(--glass-bg);
    backdrop-filter: blur(12px);
    border: 2px solid var(--glass-border);
    border-radius: 24px;
    padding: 24px 16px;
    text-align: center;
    cursor: pointer;
    box-shadow: var(--shadow-sm);
    transition: transform 0.3s cubic-bezier(0.2, 1, 0.22, 1), box-shadow 0.3s, background 0.3s;
    animation: popCard 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.1) both;
}

/* 動態計算卡片延遲載入 */
.lobby-card:nth-child(1) { animation-delay: 0.05s; }
.lobby-card:nth-child(2) { animation-delay: 0.1s; }
.lobby-card:nth-child(3) { animation-delay: 0.15s; }
.lobby-card:nth-child(4) { animation-delay: 0.2s; }
.lobby-card:nth-child(5) { animation-delay: 0.25s; }
.lobby-card:nth-child(6) { animation-delay: 0.3s; }
.lobby-card:nth-child(7) { animation-delay: 0.35s; }
.lobby-card:nth-child(8) { animation-delay: 0.4s; }

.lobby-card:hover {
    transform: translateY(-8px) scale(1.03);
    background: rgba(255, 255, 255, 0.9);
    box-shadow: var(--shadow-lg);
    border-color: rgba(255, 255, 255, 0.8);
}

.card-avatar {
    font-size: 52px;
    margin-bottom: 12px;
    transition: transform 0.3s ease;
}

.lobby-card:hover .card-avatar {
    transform: scale(1.15) rotate(5deg);
}

.card-title {
    font-size: 20px;
    font-weight: 800;
    color: #212529;
    margin-bottom: 8px;
}

.lobby-card p {
    font-size: 13px;
    color: var(--text-muted);
}

.btn-back-home {
    background: #e9ecef;
    color: #495057;
    font-size: 16px;
    padding: 10px 24px;
}

.btn-back-home:hover {
    background: #dee2e6;
    transform: translateY(-1px);
}

@keyframes popCard {
    0% { opacity: 0; transform: translateY(40px) scale(0.9); }
    100% { opacity: 1; transform: translateY(0) scale(1); }
}

/* ------------------ 複習單元共用樣式 ------------------ */
.activity {
    background: linear-gradient(135deg, #f8f9fa 0%, #e9ecef 100%);
    justify-content: space-between;
}

.nav-header {
    width: 100%;
    max-width: 1000px;
    display: flex;
    justify-content: space-between;
    align-items: center;
    border-bottom: 2px solid #dee2e6;
    padding-bottom: 15px;
    margin-bottom: 20px;
}

.nav-header .title {
    font-size: 28px;
    font-weight: 900;
    color: #343a40;
}

.btn-nav {
    font-family: var(--font-cute);
    font-weight: 700;
    background: var(--primary);
    color: white;
    padding: 8px 20px;
    border: none;
    border-radius: 12px;
    cursor: pointer;
    box-shadow: var(--shadow-sm);
    transition: all 0.2s;
}

.btn-nav:hover {
    background: #4c6ef5;
    transform: translateY(-1px);
}

.slide-container {
    flex-grow: 1;
    display: flex;
    justify-content: center;
    align-items: center;
    width: 100%;
    max-width: 1000px;
}

.bottom-controls {
    width: 100%;
    max-width: 600px;
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-top: 20px;
}

.btn-arrow {
    background: white;
    color: var(--text-color);
    font-size: 16px;
    padding: 10px 24px;
    border: 2px solid #dee2e6;
}

.btn-arrow:hover {
    background: var(--primary-light);
    border-color: var(--primary);
    color: var(--primary);
    transform: translateY(-1px);
}

.page-number {
    font-family: var(--font-cute);
    font-size: 18px;
    font-weight: bold;
    color: #495057;
}

.score-display, .timer-box {
    font-family: var(--font-cute);
    font-size: 20px;
    font-weight: 700;
    background: #fff;
    padding: 8px 16px;
    border-radius: 15px;
    box-shadow: var(--shadow-sm);
}

.timer-box {
    color: var(--accent);
}

/* ------------------ 1. 聽寫選字 ------------------ */
.dict-box {
    background: #fff;
    border-radius: 24px;
    padding: 40px;
    width: 100%;
    max-width: 650px;
    text-align: center;
    box-shadow: var(--shadow-md);
    border: 3px dashed #d0bfff;
}

.btn-speak {
    font-family: var(--font-cute);
    background: linear-gradient(135deg, #ae3ec9 0%, #862e9c 100%);
    color: white;
    border: none;
    padding: 20px 40px;
    font-size: 26px;
    border-radius: 20px;
    cursor: pointer;
    margin-bottom: 25px;
    box-shadow: 0 10px 15px rgba(134, 46, 156, 0.2);
    transition: all 0.2s;
}

.btn-speak:hover {
    transform: scale(1.05);
    box-shadow: 0 12px 20px rgba(134, 46, 156, 0.3);
}

.dict-hint {
    font-size: 18px;
    color: #495057;
    margin-bottom: 25px;
}

.options-container {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 20px;
    margin-bottom: 20px;
}

.option-btn {
    font-family: var(--font-normal);
    background: #f8f9fa;
    border: 2px solid #dee2e6;
    border-radius: 16px;
    padding: 25px;
    font-size: 32px;
    font-weight: bold;
    cursor: pointer;
    transition: all 0.2s ease;
    box-shadow: var(--shadow-sm);
}

.option-btn:hover {
    background: #e9ecef;
    border-color: #ced4da;
    transform: translateY(-2px);
}

.option-btn.correct-choice {
    background: #ebfbee;
    border-color: var(--success);
    color: #2b8a3e;
}

.option-btn.wrong-choice {
    background: #fff5f5;
    border-color: var(--danger);
    color: #c92a2a;
}

.feedback-msg {
    font-size: 22px;
    font-weight: 800;
    margin-top: 15px;
    min-height: 33px;
}

.feedback-msg.correct { color: var(--success); }
.feedback-msg.wrong { color: var(--danger); }

/* ------------------ 2. 部首造詞 ------------------ */
.radical-controls {
    position: absolute;
    top: 120px;
    z-index: 10;
}

.btn-timer-start {
    background: var(--accent);
    color: white;
    font-size: 16px;
    padding: 8px 20px;
}

.flashcard-container {
    width: 320px;
    height: 400px;
    perspective: 1000px;
    margin-top: 40px;
}

.flashcard {
    width: 100%;
    height: 100%;
    position: relative;
    transform-style: preserve-3d;
    transition: transform 0.6s cubic-bezier(0.4, 0, 0.2, 1);
    cursor: pointer;
}

.flashcard.flipped {
    transform: rotateY(180deg);
}

.card-face {
    position: absolute;
    width: 100%;
    height: 100%;
    backface-visibility: hidden;
    border-radius: 30px;
    display: flex;
    flex-direction: column;
    justify-content: space-between;
    align-items: center;
    padding: 30px;
    box-shadow: var(--shadow-lg);
}

.card-front {
    background: linear-gradient(135deg, #fff9db 0%, #fff3bf 100%);
    border: 4px solid #fab005;
}

.character-display {
    font-size: 120px;
    font-weight: 900;
    color: #e67700;
    margin-top: auto;
    margin-bottom: auto;
}

.click-hint {
    font-size: 14px;
    color: #f76707;
    font-weight: bold;
    letter-spacing: 1px;
}

.card-back {
    background: white;
    border: 4px solid #20b2aa;
    transform: rotateY(180deg);
}

.info-group {
    width: 100%;
    margin-bottom: 20px;
    text-align: center;
}

.info-group h3 {
    font-size: 16px;
    color: #495057;
    border-bottom: 2px dashed #e9ecef;
    padding-bottom: 6px;
    margin-bottom: 12px;
}

.info-radical {
    font-size: 32px;
    font-weight: bold;
    color: #008080;
}

.info-words {
    font-size: 26px;
    font-weight: bold;
    color: #212529;
}

/* ------------------ 3. 改錯字 ------------------ */
.question-card, .phrase-card, .sentence-card, .qa-card, .idiom-card {
    background: #fff;
    border-radius: 28px;
    padding: 40px;
    width: 100%;
    max-width: 750px;
    box-shadow: var(--shadow-md);
    display: flex;
    flex-direction: column;
    align-items: center;
    min-height: 380px;
    justify-content: space-between;
}

.sentence-box {
    font-size: 28px;
    font-weight: bold;
    color: #343a40;
    line-height: 1.6;
    text-align: center;
    width: 100%;
    margin-bottom: 30px;
}

.wrong-char-hl {
    color: var(--danger);
    border-bottom: 3px wavy var(--danger);
    padding: 0 4px;
}

.answer-box {
    display: flex;
    justify-content: center;
    gap: 40px;
    width: 100%;
    margin-bottom: 30px;
    animation: fadeInUp 0.4s ease-out;
}

.wrong-cross, .correct-check {
    font-size: 24px;
    font-weight: bold;
    padding: 12px 24px;
    border-radius: 16px;
}

.wrong-cross {
    background: #fff5f5;
    color: #c92a2a;
    border: 2px solid #ffc9c9;
}

.correct-check {
    background: #ebfbee;
    color: #2b8a3e;
    border: 2px solid #b2f2bb;
}

.bopomofo {
    font-family: var(--font-cute);
    color: #f76707;
    margin-left: 8px;
    font-size: 18px;
}

.btn-show-ans {
    background: linear-gradient(135deg, #15aabf 0%, #0b7285 100%);
    color: white;
}

.btn-show-ans:hover {
    transform: scale(1.03);
    box-shadow: 0 10px 15px rgba(11, 114, 133, 0.2);
}

.hidden {
    opacity: 0;
    transform: scale(0.95);
    pointer-events: none;
    display: none !important;
}

/* ------------------ 4. 短語練習 ------------------ */
.phrase-card {
    align-items: stretch;
}

.phrase-origin, .phrase-structure, .phrase-example {
    margin-bottom: 20px;
}

.phrase-card h3 {
    font-size: 15px;
    color: var(--text-muted);
    margin-bottom: 6px;
}

.phrase-card .text {
    font-size: 26px;
    font-weight: bold;
    color: #212529;
}

.phrase-card .structure-text {
    font-size: 18px;
    color: var(--primary);
    background: var(--primary-light);
    display: inline-block;
    padding: 6px 14px;
    border-radius: 10px;
    font-weight: bold;
}

.phrase-card .example-text {
    font-size: 26px;
    font-weight: bold;
    color: var(--success);
    background: #ebfbee;
    padding: 10px 16px;
    border-radius: 12px;
    border-left: 5px solid var(--success);
}

/* ------------------ 5. 造句展示 ------------------ */
.sentence-card {
    align-items: stretch;
}

.pattern-box {
    background: #fff9db;
    border: 2px solid #ffe066;
    padding: 16px;
    border-radius: 16px;
    margin-bottom: 24px;
}

.pattern-box h3, .examples-container h3 {
    font-size: 15px;
    color: #e67700;
    margin-bottom: 6px;
}

.examples-container h3 {
    color: var(--primary);
}

.pattern-text {
    font-size: 26px;
    font-weight: bold;
    color: #d9480f;
}

.example-list {
    list-style-type: none;
}

.example-list li {
    font-size: 20px;
    line-height: 1.6;
    color: #343a40;
    padding: 12px 10px;
    border-bottom: 1px solid #f1f3f5;
    display: flex;
    align-items: flex-start;
}

.example-list li::before {
    content: '⭐';
    margin-right: 10px;
    font-size: 16px;
    margin-top: 4px;
}

/* ------------------ 6. 課文問答 ------------------ */
.qa-card {
    justify-content: flex-start;
}

.qa-lesson {
    background: #e8f5e9;
    color: #2e7d32;
    font-size: 14px;
    font-weight: bold;
    padding: 4px 14px;
    border-radius: 20px;
    margin-bottom: 20px;
}

.qa-question {
    font-size: 26px;
    font-weight: 800;
    color: #1e293b;
    text-align: center;
    line-height: 1.5;
    margin-bottom: 30px;
}

.qa-answer {
    font-size: 22px;
    color: #3b82f6;
    background: #eff6ff;
    border: 2px solid #bfdbfe;
    border-radius: 20px;
    padding: 24px;
    width: 100%;
    text-align: center;
    line-height: 1.6;
    font-weight: bold;
    margin-bottom: 30px;
    animation: fadeInUp 0.4s ease-out;
}

/* ------------------ 7. 看圖猜成語 ------------------ */
.idiom-card {
    min-height: 480px;
}

.idiom-img-container {
    width: 100%;
    max-width: 400px;
    height: 250px;
    background: #f1f3f5;
    border-radius: 20px;
    overflow: hidden;
    box-shadow: var(--shadow-sm);
    margin-bottom: 20px;
    display: flex;
    justify-content: center;
    align-items: center;
}

.idiom-img-container img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.idiom-answer {
    text-align: center;
    margin-bottom: 20px;
    animation: scaleIn 0.3s ease-out;
}

.idiom-answer h2 {
    font-family: var(--font-cute);
    font-size: 38px;
    color: #e64980;
    letter-spacing: 2px;
}

/* ------------------ 8. 幸運抽獎 ------------------ */
.lottery-container {
    flex-grow: 1;
    width: 100%;
    max-width: 1100px;
    display: flex;
    justify-content: center;
    align-items: center;
    margin: 20px 0;
}

.lottery-grid {
    display: grid;
    grid-template-columns: repeat(5, 1fr);
    gap: 15px;
    width: 100%;
}

.lottery-card {
    height: 140px;
    background: linear-gradient(135deg, #ff6b6b 0%, #fa5252 100%);
    border-radius: 20px;
    border: 3px solid #ffe3e3;
    cursor: pointer;
    box-shadow: var(--shadow-md);
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: center;
    transition: all 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275);
    position: relative;
    transform-style: preserve-3d;
}

.lottery-card:hover {
    transform: scale(1.05) translateY(-5px);
    box-shadow: var(--shadow-lg);
}

.lottery-card.revealed {
    transform: rotateY(180deg);
    background: #fff;
    border-color: #ffd43b;
    cursor: default;
}

.lottery-card .front-content {
    font-size: 40px;
    font-weight: bold;
    color: #fff;
    backface-visibility: hidden;
}

.lottery-card .back-content {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: center;
    transform: rotateY(180deg);
    backface-visibility: hidden;
    padding: 10px;
    text-align: center;
    font-size: 16px;
    font-weight: bold;
    color: #212529;
}

/* 彈出視窗 */
.modal-overlay {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(0,0,0,0.5);
    backdrop-filter: blur(8px);
    z-index: 10000;
    display: flex;
    justify-content: center;
    align-items: center;
    opacity: 0;
    pointer-events: none;
    transition: opacity 0.3s ease;
}

.modal-overlay.active {
    opacity: 1;
    pointer-events: auto;
}

.modal-content {
    background: white;
    border-radius: 30px;
    padding: 40px;
    text-align: center;
    width: 90%;
    max-width: 450px;
    box-shadow: var(--shadow-lg);
    border: 5px solid #ffcc00;
    transform: scale(0.8);
    transition: transform 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275);
    position: relative;
}

.modal-overlay.active .modal-content {
    transform: scale(1);
}

.modal-close {
    position: absolute;
    top: 15px;
    right: 20px;
    font-size: 28px;
    cursor: pointer;
    color: var(--text-muted);
}

.modal-avatar {
    font-size: 72px;
    margin-bottom: 15px;
    animation: bounce 1.5s infinite;
}

.modal-title {
    font-size: 24px;
    color: #495057;
    margin-bottom: 10px;
}

.modal-prize {
    font-size: 32px;
    font-weight: 900;
    color: #ff922b;
    margin-bottom: 30px;
    line-height: 1.4;
}

@keyframes bounce {
    0%, 100% { transform: translateY(0); }
    50% { transform: translateY(-15px); }
}

/* ------------------ 動畫與細部動畫 ------------------ */
@keyframes fadeInDown {
    0% { opacity: 0; transform: translateY(-20px); }
    100% { opacity: 1; transform: translateY(0); }
}

@keyframes fadeInUp {
    0% { opacity: 0; transform: translateY(20px); }
    100% { opacity: 1; transform: translateY(0); }
}

@keyframes scaleIn {
    0% { opacity: 0; transform: scale(0.9); }
    100% { opacity: 1; transform: scale(1); }
}

