// ==========================================
// 2. 音效生成器 (Web Audio API)
// ==========================================
class SoundEffects {
    constructor() {
        this.ctx = null;
        this.muted = false;
    }

    init() {
        if (!this.ctx) {
            this.ctx = new (window.AudioContext || window.webkitAudioContext)();
        }
        if (this.ctx.state === 'suspended') {
            this.ctx.resume();
        }
    }

    playCorrect() {
        if (this.muted) return;
        this.init();
        const t = this.ctx.currentTime;
        this.playTone(523.25, 'sine', t, 0.15); // C5
        this.playTone(659.25, 'sine', t + 0.1, 0.15); // E5
        this.playTone(783.99, 'sine', t + 0.2, 0.3); // G5
    }

    playWrong() {
        if (this.muted) return;
        this.init();
        const t = this.ctx.currentTime;
        this.playTone(220, 'sawtooth', t, 0.2); // A3
        this.playTone(196, 'sawtooth', t + 0.15, 0.4); // G3
    }

    playWin() {
        if (this.muted) return;
        this.init();
        const t = this.ctx.currentTime;
        const notes = [523.25, 587.33, 659.25, 698.46, 783.99, 880.00, 987.77, 1046.50];
        notes.forEach((freq, idx) => {
            this.playTone(freq, 'sine', t + idx * 0.08, 0.15);
        });
    }

    playTick() {
        if (this.muted) return;
        this.init();
        this.playTone(800, 'sine', this.ctx.currentTime, 0.03, 0.2);
    }

    playTimeUp() {
        if (this.muted) return;
        this.init();
        const t = this.ctx.currentTime;
        this.playTone(300, 'sawtooth', t, 0.3);
        this.playTone(300, 'sawtooth', t + 0.35, 0.3);
    }

    playTone(freq, type, startTime, duration, volume = 0.5) {
        const osc = this.ctx.createOscillator();
        const gain = this.ctx.createGain();
        osc.type = type;
        osc.frequency.setValueAtTime(freq, startTime);
        gain.gain.setValueAtTime(volume, startTime);
        gain.gain.exponentialRampToValueAtTime(0.01, startTime + duration);
        osc.connect(gain);
        gain.connect(this.ctx.destination);
        osc.start(startTime);
        osc.stop(startTime + duration);
    }
}

