        });

        // 綁定主選單卡片
        document.querySelectorAll('.lobby-card').forEach(card => {
            card.addEventListener('click', (e) => {
                const target = card.getAttribute('data-target');
                this.switchScene(target);
                this.loadActivity(target);
            });
        });

        // 各單元按鈕綁定
        this.bindEvents();
    },

    switchScene(sceneId) {
        document.querySelectorAll('.scene').forEach(scene => {
            scene.classList.remove('active');
        });
        document.getElementById(sceneId).classList.add('active');
    },

    loadActivity(type) {
        switch(type) {
            case 'dictation':
                this.dictIdx = 0;
                this.dictCorrectCount = 0;
                this.showDictation();
                break;
            case 'radicals':
                this.radIdx = 0;
                this.stopTimer();
                this.radTimeLeft = 60;
                document.getElementById('timerVal').innerText = 60;
                document.getElementById('radicalCard').classList.remove('flipped');
                document.getElementById('startTimerBtn').style.display = 'inline-block';
                document.getElementById('resetTimerBtn').style.display = 'none';
                this.showRadical();
                break;
            case 'errors':
                this.errIdx = 0;
                this.showError();
                break;
            case 'phrases':
                this.phraseIdx = 0;
                this.showPhrase();
                break;
            case 'sentences':
                this.sentIdx = 0;
                this.showSentence();
                break;
            case 'qa':
                this.qaIdx = 0;
                this.showQa();
                break;
            case 'idioms':
                this.idiomIdx = 0;
                this.showIdiom();
                break;
            case 'lottery':
                this.initLottery();
                break;
        }
    },

    bindEvents() {
        // 1. 聽寫選字
        document.getElementById('btnSpeak').addEventListener('click', () => this.speakWord());
        document.getElementById('opt1').addEventListener('click', (e) => this.checkDictation(e));
        document.getElementById('opt2').addEventListener('click', (e) => this.checkDictation(e));
        document.getElementById('dictPrev').addEventListener('click', () => {
            if (this.dictIdx > 0) { this.dictIdx--; this.showDictation(); }
        });
        document.getElementById('dictNext').addEventListener('click', () => {
            if (this.dictIdx < DATA.dictation.length - 1) { this.dictIdx++; this.showDictation(); }
        });

        // 2. 部首與造詞
        document.getElementById('radicalCard').addEventListener('click', () => {
            document.getElementById('radicalCard').classList.toggle('flipped');
        });
        document.getElementById('radPrev').addEventListener('click', () => {
            if (this.radIdx > 0) { 
                this.radIdx--; 
                document.getElementById('radicalCard').classList.remove('flipped');
                setTimeout(() => this.showRadical(), 150); 
            }
        });
        document.getElementById('radNext').addEventListener('click', () => {
            if (this.radIdx < DATA.radicals.length - 1) { 
                this.radIdx++; 
                document.getElementById('radicalCard').classList.remove('flipped');
                setTimeout(() => this.showRadical(), 150);
            }
        });
        document.getElementById('startTimerBtn').addEventListener('click', () => this.startTimer());
        document.getElementById('resetTimerBtn').addEventListener('click', () => this.resetTimer());

        // 3. 改錯字
        document.getElementById('btnShowErrAns').addEventListener('click', () => {
            document.getElementById('errAnswerBox').classList.toggle('hidden');
        });
        document.getElementById('errPrev').addEventListener('click', () => {
            if (this.errIdx > 0) { this.errIdx--; this.showError(); }
        });
        document.getElementById('errNext').addEventListener('click', () => {
            if (this.errIdx < DATA.errors.length - 1) { this.errIdx++; this.showError(); }
        });

        // 4. 短語練習
        document.getElementById('btnShowPhraseAns').addEventListener('click', () => {
            document.getElementById('phraseExample').classList.toggle('hidden');
        });
        document.getElementById('phrasePrev').addEventListener('click', () => {
            if (this.phraseIdx > 0) { this.phraseIdx--; this.showPhrase(); }
        });
        document.getElementById('phraseNext').addEventListener('click', () => {
            if (this.phraseIdx < DATA.phrases.length - 1) { this.phraseIdx++; this.showPhrase(); }
        });

        // 5. 造句展示
        document.getElementById('sentPrev').addEventListener('click', () => {
            if (this.sentIdx > 0) { this.sentIdx--; this.showSentence(); }
        });
        document.getElementById('sentNext').addEventListener('click', () => {
            if (this.sentIdx < DATA.sentences.length - 1) { this.sentIdx++; this.showSentence(); }
        });

        // 6. 課文問答
        document.getElementById('btnShowQaAns').addEventListener('click', () => {
            document.getElementById('qaAnswer').classList.toggle('hidden');
        });
        document.getElementById('qaPrev').addEventListener('click', () => {
            if (this.qaIdx > 0) { this.qaIdx--; this.showQa(); }
        });
        document.getElementById('qaNext').addEventListener('click', () => {
            if (this.qaIdx < DATA.qa.length - 1) { this.qaIdx++; this.showQa(); }
        });

        // 7. 看圖猜成語
        document.getElementById('btnShowIdiomAns').addEventListener('click', () => {
            document.getElementById('idiomAnswer').classList.toggle('hidden');
        });
        document.getElementById('idiomPrev').addEventListener('click', () => {
            if (this.idiomIdx > 0) { this.idiomIdx--; this.showIdiom(); }
        });
        document.getElementById('idiomNext').addEventListener('click', () => {
            if (this.idiomIdx < DATA.idioms.length - 1) { this.idiomIdx++; this.showIdiom(); }
        });

        // 8. 幸運抽獎
        document.getElementById('shuffleLotteryBtn').addEventListener('click', () => this.shuffleLottery());
        document.getElementById('modalClose').addEventListener('click', () => this.closeModal());
        document.getElementById('modalConfirm').addEventListener('click', () => this.closeModal());
    },

    // ==========================================
    // 聽寫選字邏輯
    // ==========================================
    showDictation() {
        const item = DATA.dictation[this.dictIdx];
        document.getElementById('dictPage').innerText = `${this.dictIdx + 1}/${DATA.dictation.length}`;
        document.getElementById('dictFeedback').className = 'feedback-msg';
        document.getElementById('dictFeedback').innerText = '';

        // 更新得分
        document.getElementById('dictScore').innerText = this.dictCorrectCount;
        document.getElementById('dictTotal').innerText = DATA.dictation.length;

        // 隨機排列選項左右位置
        const rand = Math.random() > 0.5;
        const opt1 = document.getElementById('opt1');
        const opt2 = document.getElementById('opt2');

        opt1.className = 'option-btn';
        opt2.className = 'option-btn';
        opt1.disabled = false;
        opt2.disabled = false;

        if (rand) {
            opt1.innerText = `1. ${item.word}`;
            opt1.setAttribute('data-correct', 'true');
            opt2.innerText = `2. ${item.wrong}`;
            opt2.setAttribute('data-correct', 'false');
        } else {
            opt1.innerText = `1. ${item.wrong}`;
            opt1.setAttribute('data-correct', 'false');
            opt2.innerText = `2. ${item.word}`;
            opt2.setAttribute('data-correct', 'true');
        }

        // 自動播放語音
        setTimeout(() => this.speakWord(), 400);
    },

    speakWord() {
        const word = DATA.dictation[this.dictIdx].word;
        if ('speechSynthesis' in window) {
            window.speechSynthesis.cancel(); // 停止目前播放
            const utterance = new SpeechSynthesisUtterance(word);
            utterance.lang = 'zh-TW';
            utterance.rate = 0.8; // 稍慢的速度適合聽寫
            window.speechSynthesis.speak(utterance);
        } else {
            alert('抱歉，您的瀏覽器不支援語音合成！');
        }
    },

    checkDictation(e) {
        const btn = e.target;
        const isCorrect = btn.getAttribute('data-correct') === 'true';
        const opt1 = document.getElementById('opt1');
        const opt2 = document.getElementById('opt2');
        const feedback = document.getElementById('dictFeedback');

        opt1.disabled = true;
        opt2.disabled = true;

        if (isCorrect) {
            btn.classList.add('correct-choice');
            feedback.innerText = '答對了！你真棒！ 🎉';
            feedback.className = 'feedback-msg correct';
            this.dictCorrectCount++;
            document.getElementById('dictScore').innerText = this.dictCorrectCount;
            sfx.playCorrect();
        } else {
            btn.classList.add('wrong-choice');
            // 將正確選項上綠色
            if (opt1.getAttribute('data-correct') === 'true') opt1.classList.add('correct-choice');
            if (opt2.getAttribute('data-correct') === 'true') opt2.classList.add('correct-choice');

            feedback.innerText = '答錯了，再接再厲！';
            feedback.className = 'feedback-msg wrong';
            sfx.playWrong();
        }
    },

    // ==========================================
    // 部首與造詞邏輯
    // ==========================================
    showRadical() {
        const item = DATA.radicals[this.radIdx];
        document.getElementById('radPage').innerText = `${this.radIdx + 1}/${DATA.radicals.length}`;
        document.getElementById('radChar').innerText = item.char;
        document.getElementById('radName').innerText = item.radical;
        document.getElementById('radWords').innerText = item.words;
    },

    startTimer() {
        this.stopTimer();
        this.radTimeLeft = 60;
        document.getElementById('timerVal').innerText = this.radTimeLeft;
        document.getElementById('startTimerBtn').style.display = 'none';
        document.getElementById('resetTimerBtn').style.display = 'inline-block';

        this.radTimer = setInterval(() => {
            this.radTimeLeft--;
            document.getElementById('timerVal').innerText = this.radTimeLeft;

            if (this.radTimeLeft <= 10 && this.radTimeLeft > 0) {
                sfx.playTick();
            }

            if (this.radTimeLeft <= 0) {
                this.stopTimer();
                sfx.playTimeUp();
                alert('時間到！時間過得真快！');
            }
        }, 1000);
    },

    stopTimer() {
        if (this.radTimer) {
            clearInterval(this.radTimer);
            this.radTimer = null;
        }
    },

    resetTimer() {
        this.stopTimer();
        this.radTimeLeft = 60;
        document.getElementById('timerVal').innerText = 60;
        document.getElementById('startTimerBtn').style.display = 'inline-block';
        document.getElementById('resetTimerBtn').style.display = 'none';
    },

    // ==========================================
    // 改錯字邏輯
    // ==========================================
    showError() {
        const item = DATA.errors[this.errIdx];
        document.getElementById('errPage').innerText = `${this.errIdx + 1}/${DATA.errors.length}`;
        document.getElementById('errSentence').innerHTML = item.sentence;
        document.getElementById('errWrong').innerText = item.wrong;
        document.getElementById('errRight').innerText = item.right;
        document.getElementById('errBopo').innerText = item.bopo;
        document.getElementById('errAnswerBox').classList.add('hidden');
    },

    // ==========================================
    // 短語練習邏輯
    // ==========================================
    showPhrase() {
        const item = DATA.phrases[this.phraseIdx];
        document.getElementById('phrasePage').innerText = `${this.phraseIdx + 1}/${DATA.phrases.length}`;
        document.getElementById('phraseOrig').innerText = item.orig;
        document.getElementById('phraseStruct').innerText = item.struct;
        document.getElementById('phraseExText').innerText = item.ex;
        document.getElementById('phraseExample').classList.add('hidden');
    },

    // ==========================================
    // 造句展示邏輯
    // ==========================================
    showSentence() {
        const item = DATA.sentences[this.sentIdx];
        document.getElementById('sentPage').innerText = `${this.sentIdx + 1}/${DATA.sentences.length}`;
        document.getElementById('sentPattern').innerText = item.pattern;

        const list = document.getElementById('sentExList');
        list.innerHTML = '';
        item.examples.forEach(ex => {
            const li = document.createElement('li');
            li.innerText = ex;
            list.appendChild(li);
        });
    },

    // ==========================================
    // 課文問答邏輯
    // ==========================================
    showQa() {
        const item = DATA.qa[this.qaIdx];
        document.getElementById('qaPage').innerText = `${this.qaIdx + 1}/${DATA.qa.length}`;
        document.getElementById('qaLesson').innerText = item.lesson;
        document.getElementById('qaQuestion').innerText = item.question;
        document.getElementById('qaAnswer').innerText = item.answer;
        document.getElementById('qaAnswer').classList.add('hidden');
    },

    // ==========================================
    // 看圖猜成語邏輯
    // ==========================================
    showIdiom() {
        const item = DATA.idioms[this.idiomIdx];
        document.getElementById('idiomPage').innerText = `${this.idiomIdx + 1}/${DATA.idioms.length}`;
        document.getElementById('idiomImg').src = item.img;
        document.getElementById('idiomAnswer').querySelector('h2').innerText = item.title;
        document.getElementById('idiomBopo').innerText = item.bopo;
        document.getElementById('idiomAnswer').classList.add('hidden');
    },

    // ==========================================
    // 幸運抽獎邏輯 (打亂並渲染卡片)
    // ==========================================
    initLottery() {
        this.shuffleLottery();
    },

    shuffleLottery() {
        // 將獎項隨機排序
        const prizes = [...DATA.lottery];
        for (let i = prizes.length - 1; i > 0; i--) {
            const j = Math.floor(Math.random() * (i + 1));
            [prizes[i], prizes[j]] = [prizes[j], prizes[i]];
        }

        // 渲染 15 張卡片
        const grid = document.getElementById('lotteryGrid');
        grid.innerHTML = '';

        prizes.forEach((prize, idx) => {
            const card = document.createElement('div');
            card.className = 'lottery-card';
            card.innerHTML = `
                <div class="front-content">?</div>
                <div class="back-content">${prize}</div>
            `;
            card.addEventListener('click', () => this.revealLottery(card, prize));
            grid.appendChild(card);
        });
    },

    revealLottery(card, prize) {
        if (card.classList.contains('revealed')) return;

        // 翻開卡片
        card.classList.add('revealed');
        sfx.playWin();

        // 彈出對話框展示結果
        setTimeout(() => {
            document.getElementById('modalPrize').innerText = prize;
            document.getElementById('lotteryModal').classList.add('active');
        }, 600);
    },

    closeModal() {
        document.getElementById('lotteryModal').classList.remove('active');
    }
};

// 頁面加載後執行初始化
window.addEventListener('DOMContentLoaded', () => {
    UI.init();
});

