    color: #e67700;
    margin-top: auto;
    margin-bottom: auto;
}

.click-hint {
    font-size: 14px;
    color: #f76707;
    font-weight: bold;
    letter-spacing: 1px;
}

.card-back {
    background: white;
    border: 4px solid #20b2aa;
    transform: rotateY(180deg);
}

.info-group {
    width: 100%;
    margin-bottom: 20px;
    text-align: center;
}

.info-group h3 {
    font-size: 16px;
