    .vocab-definition { font-size: 17px; margin-bottom: 10px; }
    .vocab-opt-btn { font-size: 16px; padding: 8px 16px; }

    /* ---- 8. 生詞辨別 ---- */
    .discrim-sentence { font-size: 20px; margin-bottom: 18px; }
