    .discrim-opt-btn { font-size: 22px; padding: 12px 24px; }

    /* ---- 9. 看圖猜成語 ---- */
    .idiom-img-container { height: 180px; }
    .idiom-answer h2 { font-size: 28px; }

    /* ---- 10. 射氣球 ---- */
