    .balloon-start-panel p { font-size: 14px; }
    .balloon-body { width: 72px; height: 88px; }
    .balloon-word { font-size: 16px; }
    .balloon-score-float { top: 56px; right: 14px; font-size: 16px; padding: 6px 12px; }

    /* ---- 11. 幸運抽獎 ---- */
    .lottery-grid { grid-template-columns: repeat(3, 1fr); gap: 8px; }
    .lottery-card { height: 100px; border-radius: 14px; }
    .lottery-card .front-content { font-size: 28px; }
    .lottery-card .back-content { font-size: 12px; }

    /* ---- Modal ---- */
    .modal-content { padding: 28px 20px; border-radius: 20px; }
    .modal-avatar { font-size: 52px; }
    .modal-title { font-size: 18px; }
    .modal-prize { font-size: 22px; }
