/* ---- 🏆 積分表系統 ---- */

/* 懸浮按鈕 */
.score-fab {
    position: fixed;
    bottom: 28px;
    left: 28px;
    z-index: 5000;
    width: 60px;
    height: 60px;
    border-radius: 50%;
    border: none;
    background: linear-gradient(135deg, #ffd43b, #fab005);
    font-size: 26px;
    cursor: pointer;
    box-shadow: 0 6px 20px rgba(250, 176, 5, 0.45);
    transition: transform 0.2s, box-shadow 0.2s;
    display: flex;
    justify-content: center;
    align-items: center;
}
.score-fab:hover {
    transform: scale(1.12) translateY(-3px);
    box-shadow: 0 10px 28px rgba(250, 176, 5, 0.55);
}
.fab-badge {
    position: absolute;
    top: -4px;
    right: -4px;
    background: #f03e3e;
    color: white;
    font-size: 11px;
    font-weight: 900;
    width: 22px;
    height: 22px;
    border-radius: 50%;
    display: flex;
    justify-content: center;
    align-items: center;
    border: 2px solid white;
    font-family: var(--font-cute);
}

/* 積分面板遮罩 */
.scoreboard-overlay {
    position: fixed;
    inset: 0;
    z-index: 9000;
    background: rgba(0, 0, 0, 0.45);
    backdrop-filter: blur(4px);
    opacity: 0;
    pointer-events: none;
    transition: opacity 0.3s ease;
}
.scoreboard-overlay.active {
    opacity: 1;
    pointer-events: auto;
}

/* 積分面板主體 */
.scoreboard-panel {
    position: absolute;
    top: 0;
    right: 0;
    width: 360px;
    height: 100%;
    background: linear-gradient(160deg, #1a1a2e 0%, #16213e 60%, #0f3460 100%);
    display: flex;
    flex-direction: column;
    transform: translateX(100%);
    transition: transform 0.4s cubic-bezier(0.25, 0.8, 0.25, 1);
    box-shadow: -8px 0 32px rgba(0, 0, 0, 0.4);
}
.scoreboard-overlay.active .scoreboard-panel {
    transform: translateX(0);
}

/* 積分面板標頭 */
.scoreboard-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 24px 20px 18px;
    border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}
.scoreboard-header h2 {
    font-family: var(--font-cute);
    font-size: 22px;
    color: #ffd43b;
    letter-spacing: 1px;
}
.sb-close {
    background: rgba(255,255,255,0.1);
    border: none;
    color: #adb5bd;
    width: 34px;
    height: 34px;
    border-radius: 50%;
    font-size: 16px;
    cursor: pointer;
    transition: background 0.2s;
    display: flex;
    align-items: center;
    justify-content: center;
}
.sb-close:hover { background: rgba(255,255,255,0.2); color: white; }

/* 新增組別區 */
.sb-add-team {
    display: flex;
    gap: 8px;
    padding: 16px 18px;
    border-bottom: 1px solid rgba(255,255,255,0.08);
}
.team-name-input {
    flex: 1;
    padding: 10px 14px;
    background: rgba(255,255,255,0.08);
    border: 1px solid rgba(255,255,255,0.2);
    border-radius: 12px;
    color: white;
    font-size: 15px;
    font-family: var(--font-normal);
    outline: none;
    transition: border-color 0.2s;
}
.team-name-input::placeholder { color: rgba(255,255,255,0.35); }
.team-name-input:focus { border-color: #ffd43b; }
.btn-add-team {
    padding: 10px 16px;
    background: linear-gradient(135deg, #ffd43b, #fab005);
    border: none;
    border-radius: 12px;
    color: #212529;
    font-size: 15px;
    font-weight: 700;
    cursor: pointer;
    white-space: nowrap;
    transition: transform 0.2s;
    font-family: var(--font-cute);
}
.btn-add-team:hover { transform: scale(1.05); }

/* 排行榜區域 */
.sb-ranking {
    flex: 1;
    overflow-y: auto;
    padding: 14px 16px;
    display: flex;
    flex-direction: column;
    gap: 10px;
}
.sb-ranking::-webkit-scrollbar { width: 4px; }
.sb-ranking::-webkit-scrollbar-track { background: transparent; }
.sb-ranking::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.2); border-radius: 2px; }

/* 單一組別排行卡 */
.rank-card {
    background: rgba(255,255,255,0.06);
    border: 1px solid rgba(255,255,255,0.1);
    border-radius: 16px;
    padding: 14px 16px;
    display: flex;
    align-items: center;
    gap: 14px;
    transition: all 0.3s ease;
    animation: slideInRank 0.4s ease-out both;
    position: relative;
    overflow: hidden;
}
.rank-card::before {
    content: '';
    position: absolute;
    left: 0;
    top: 0;
    height: 100%;
    width: 4px;
    background: var(--team-color, #ffd43b);
    border-radius: 4px 0 0 4px;
}
.rank-card.rank-1 { background: rgba(255, 212, 59, 0.12); border-color: rgba(255, 212, 59, 0.3); }
.rank-card.rank-2 { background: rgba(173, 181, 189, 0.1); border-color: rgba(173, 181, 189, 0.25); }
.rank-card.rank-3 { background: rgba(205, 127, 50, 0.1); border-color: rgba(205, 127, 50, 0.25); }

.rank-medal {
    font-size: 26px;
    min-width: 32px;
    text-align: center;
}
.rank-info { flex: 1; }
.rank-name {
    font-size: 17px;
    font-weight: 800;
    color: white;
    margin-bottom: 6px;
}
.rank-bar-bg {
    height: 7px;
    background: rgba(255,255,255,0.1);
    border-radius: 4px;
    overflow: hidden;
}
.rank-bar {
    height: 100%;
    border-radius: 4px;
    background: var(--team-color, #ffd43b);
    transition: width 0.6s cubic-bezier(0.25, 0.8, 0.25, 1);
    min-width: 4px;
}
.rank-score-box {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 4px;
}
.rank-score {
    font-family: var(--font-cute);
    font-size: 28px;
    font-weight: 700;
    color: white;
    line-height: 1;
    transition: transform 0.2s;
}
.rank-score.bumped { animation: scoreBump 0.4s ease-out; }
.rank-actions {
    display: flex;
    gap: 5px;
}
.rank-btn {
    width: 30px;
    height: 30px;
    border-radius: 8px;
    border: none;
    cursor: pointer;
    font-size: 16px;
    font-weight: 900;
    transition: transform 0.15s, background 0.15s;
    display: flex;
    align-items: center;
    justify-content: center;
}
.rank-btn-plus {
    background: rgba(55, 178, 77, 0.25);
    color: #69db7c;
    border: 1px solid rgba(55, 178, 77, 0.4);
}
.rank-btn-plus:hover { background: rgba(55, 178, 77, 0.45); transform: scale(1.15); }
.rank-btn-minus {
    background: rgba(240, 62, 62, 0.2);
    color: #ff8787;
    border: 1px solid rgba(240, 62, 62, 0.35);
}
.rank-btn-minus:hover { background: rgba(240, 62, 62, 0.4); transform: scale(1.15); }
.rank-btn-del {
    background: rgba(255,255,255,0.08);
    color: #868e96;
    border: 1px solid rgba(255,255,255,0.12);
    font-size: 12px;
}
.rank-btn-del:hover { background: rgba(240,62,62,0.3); color: #ff8787; transform: scale(1.1); }

/* 空狀態 */
.sb-empty {
    text-align: center;
    color: rgba(255,255,255,0.3);
    padding: 40px 0;
    font-size: 15px;
    line-height: 1.8;
}
.sb-empty-icon { font-size: 48px; margin-bottom: 12px; }

/* 底部 */
.sb-footer {
    display: flex;
    gap: 10px;
    padding: 16px 18px;
    border-top: 1px solid rgba(255,255,255,0.08);
}
.sb-btn-reset {
    flex: 1;
    padding: 10px;
    background: rgba(240,62,62,0.18);
    border: 1px solid rgba(240,62,62,0.35);
    border-radius: 12px;
    color: #ff8787;
    font-size: 14px;
    font-weight: 700;
    cursor: pointer;
    font-family: var(--font-cute);
    transition: background 0.2s;
}
.sb-btn-reset:hover { background: rgba(240,62,62,0.35); }
.sb-btn-close2 {
    flex: 1;
    padding: 10px;
    background: rgba(255,255,255,0.08);
    border: 1px solid rgba(255,255,255,0.15);
    border-radius: 12px;
    color: #adb5bd;
    font-size: 14px;
    font-weight: 700;
    cursor: pointer;
    font-family: var(--font-cute);
    transition: background 0.2s;
}
.sb-btn-close2:hover { background: rgba(255,255,255,0.16); color: white; }

/* 加分浮動提示 */
.score-toast {
    position: fixed;
    bottom: 100px;
    left: 50%;
    transform: translateX(-50%) translateY(20px);
    background: linear-gradient(135deg, #37b24d, #2b8a3e);
    color: white;
    padding: 12px 28px;
    border-radius: 50px;
    font-family: var(--font-cute);
    font-size: 18px;
    font-weight: 700;
    z-index: 9999;
    opacity: 0;
    transition: opacity 0.3s, transform 0.3s;
    pointer-events: none;
    box-shadow: 0 8px 24px rgba(55, 178, 77, 0.4);
}
.score-toast.show {
    opacity: 1;
    transform: translateX(-50%) translateY(0);
}

@keyframes slideInRank {
    from { opacity: 0; transform: translateX(30px); }
    to { opacity: 1; transform: translateX(0); }
}
@keyframes scoreBump {
    0% { transform: scale(1); }
    40% { transform: scale(1.5); color: #ffd43b; }
    100% { transform: scale(1); }
}

