window.addEventListener('DOMContentLoaded', () => UI.init());

// ==========================================
// 🏆 積分排行榜系統
// ==========================================
const TEAM_COLORS = [
    '#4dabf7', '#ff8787', '#69db7c', '#ffd43b',
    '#da77f2', '#63e6be', '#ffa94d', '#748ffc'
];

const ScoreBoard = {
    teams: [],
    isOpen: false,
    toastTimer: null,

    init() {
        // 預設載入 A、B 兩組
        this.teams = [
            { id: 1, name: 'A 組', score: 0, color: TEAM_COLORS[0] },
            { id: 2, name: 'B 組', score: 0, color: TEAM_COLORS[1] }
        ];
        this._nextId = 3;

        // 事件綁定
        document.getElementById('scoreFab').addEventListener('click', () => this.open());
        document.getElementById('sbClose').addEventListener('click', () => this.close());
        document.getElementById('sbClose2').addEventListener('click', () => this.close());
        document.getElementById('sbResetBtn').addEventListener('click', () => this.resetAll());
        document.getElementById('addTeamBtn').addEventListener('click', () => this.addTeam());
        document.getElementById('scoreboardOverlay').addEventListener('click', e => {
            if (e.target === document.getElementById('scoreboardOverlay')) this.close();
        });
        document.getElementById('teamNameInput').addEventListener('keydown', e => {
            if (e.key === 'Enter') this.addTeam();
        });

        this.render();
    },

    open() {
        this.isOpen = true;
        document.getElementById('scoreboardOverlay').classList.add('active');
        this.render();
    },

    close() {
        this.isOpen = false;
        document.getElementById('scoreboardOverlay').classList.remove('active');
    },

    addTeam() {
        const input = document.getElementById('teamNameInput');
        const name = input.value.trim();
        if (!name) return;
        const colorIdx = (this.teams.length) % TEAM_COLORS.length;
        this.teams.push({
            id: this._nextId++,
            name,
            score: 0,
            color: TEAM_COLORS[colorIdx]
        });
        input.value = '';
        this.render();
    },

    deleteTeam(id) {
        this.teams = this.teams.filter(t => t.id !== id);
        this.render();
    },

    addScore(teamId, delta = 1) {
        const team = this.teams.find(t => t.id === teamId);
        if (!team) return;
        team.score = Math.max(0, team.score + delta);
        this.render();
        if (delta > 0) this.showToast(`${team.name} ＋${delta} 分 🎉`);
        else this.showToast(`${team.name} ${delta} 分`, 'minus');
        this._updateFabBadge();
    },

    // 外部呼叫：直接加分給第一名 or 特定隊伍
    awardPoint(teamId, points = 1) {
        this.addScore(teamId, points);
    },

    resetAll() {
        if (!confirm('確定要將所有組別的積分重置為 0？')) return;
        this.teams.forEach(t => t.score = 0);
        this.render();
        this._updateFabBadge();
    },

    render() {
        const container = document.getElementById('sbRanking');
        if (!container) return;

        if (this.teams.length === 0) {
            container.innerHTML = `
                <div class="sb-empty">
                    <div class="sb-empty-icon">🏁</div>
                    <div>還沒有組別</div>
                    <div>請在上方輸入組別名稱並新增！</div>
                </div>`;
            return;
        }

        // 依分數排序
        const sorted = [...this.teams].sort((a, b) => b.score - a.score);
        const maxScore = sorted[0].score || 1;
        const medals = ['🥇', '🥈', '🥉'];

        container.innerHTML = '';
        sorted.forEach((team, rank) => {
            const barWidth = Math.max(4, Math.round((team.score / maxScore) * 100));
            const card = document.createElement('div');
            card.className = `rank-card rank-${rank + 1}`;
            card.style.setProperty('--team-color', team.color);
            card.innerHTML = `
                <div class="rank-medal">${medals[rank] || `#${rank+1}`}</div>
                <div class="rank-info">
                    <div class="rank-name">${team.name}</div>
                    <div class="rank-bar-bg">
                        <div class="rank-bar" style="width:${barWidth}%; background:${team.color};"></div>
                    </div>
                </div>
                <div class="rank-score-box">
                    <div class="rank-score" id="score-${team.id}">${team.score}</div>
                </div>
                <div class="rank-actions">
                    <button class="rank-btn rank-btn-plus" title="加 1 分">＋</button>
                    <button class="rank-btn rank-btn-minus" title="減 1 分">－</button>
                    <button class="rank-btn rank-btn-del" title="移除組別">✕</button>
                </div>`;

            card.querySelector('.rank-btn-plus').addEventListener('click', () => this.addScore(team.id, 1));
            card.querySelector('.rank-btn-minus').addEventListener('click', () => this.addScore(team.id, -1));
            card.querySelector('.rank-btn-del').addEventListener('click', () => this.deleteTeam(team.id));

            container.appendChild(card);
        });

        this._updateFabBadge();
    },

    showToast(msg, type = 'plus') {
        const toast = document.getElementById('scoreToast');
        if (!toast) return;
        toast.innerText = msg;
        toast.style.background = type === 'minus'
            ? 'linear-gradient(135deg, #f03e3e, #c92a2a)'
            : 'linear-gradient(135deg, #37b24d, #2b8a3e)';
        toast.classList.add('show');
        if (this.toastTimer) clearTimeout(this.toastTimer);
        this.toastTimer = setTimeout(() => toast.classList.remove('show'), 2000);
    },

    _updateFabBadge() {
        const total = this.teams.reduce((s, t) => s + t.score, 0);
        const badge = document.getElementById('fabBadge');
        if (!badge) return;
        if (total > 0) {
            badge.style.display = 'flex';
            badge.innerText = total;
        } else {
            badge.style.display = 'none';
        }
    }
};

